package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat createCSVFormatWithQuoteCharacter(Character quoteChar) {
        if (quoteChar == null) {
            return CSVFormat.DEFAULT.withQuote((Character) null);
        } else {
            return CSVFormat.DEFAULT.withQuote(quoteChar.charValue());
        }
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsSet() {
        CSVFormat format = createCSVFormatWithQuoteCharacter('\"');

        assertTrue(format.isQuoteCharacterSet());
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() {
        CSVFormat format = createCSVFormatWithQuoteCharacter(null);

        assertFalse(format.isQuoteCharacterSet());
    }
}
